void x_set_minlmreport(x_minlmreport *dst, minlmreport *src, ae_state *_state)
{
    dst->iterationscount = src->iterationscount;
    dst->terminationtype = src->terminationtype;
    dst->nfunc = src->nfunc;
    dst->njac = src->njac;
    dst->ngrad = src->ngrad;
    dst->nhess = src->nhess;
    dst->ncholesky = src->ncholesky;
}
void minlmreport_init_from_x(minlmreport *dst, x_minlmreport *src, ae_state *_state, ae_bool make_automatic)
{
    dst->iterationscount = (ae_int_t)(src->iterationscount);
    dst->terminationtype = (ae_int_t)(src->terminationtype);
    dst->nfunc = (ae_int_t)(src->nfunc);
    dst->njac = (ae_int_t)(src->njac);
    dst->ngrad = (ae_int_t)(src->ngrad);
    dst->nhess = (ae_int_t)(src->nhess);
    dst->ncholesky = (ae_int_t)(src->ncholesky);
}
