void x_set_minnlcreport(x_minnlcreport *dst, minnlcreport *src, ae_state *_state)
{
    dst->iterationscount = src->iterationscount;
    dst->nfev = src->nfev;
    dst->terminationtype = src->terminationtype;
    dst->bcerr = src->bcerr;
    dst->bcidx = src->bcidx;
    dst->lcerr = src->lcerr;
    dst->lcidx = src->lcidx;
    dst->nlcerr = src->nlcerr;
    dst->nlcidx = src->nlcidx;
    dst->dbgphase0its = src->dbgphase0its;
}
void minnlcreport_init_from_x(minnlcreport *dst, x_minnlcreport *src, ae_state *_state, ae_bool make_automatic)
{
    dst->iterationscount = (ae_int_t)(src->iterationscount);
    dst->nfev = (ae_int_t)(src->nfev);
    dst->terminationtype = (ae_int_t)(src->terminationtype);
    dst->bcerr = src->bcerr;
    dst->bcidx = (ae_int_t)(src->bcidx);
    dst->lcerr = src->lcerr;
    dst->lcidx = (ae_int_t)(src->lcidx);
    dst->nlcerr = src->nlcerr;
    dst->nlcidx = (ae_int_t)(src->nlcidx);
    dst->dbgphase0its = (ae_int_t)(src->dbgphase0its);
}
